1	// Quote constants
2	const PROCESSING_FEE = 5;
3	const DEFAULT_BASE_PREMIUM = 100;
4	const CURSE_SURCHARGE_RATE = 0.5;
5	const FIRST_INSURANCE_RATE = 0.1;
6	const HIGH_ENCHANTMENT_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_THRESHOLD_YEARS = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	// Claim constants
13	const DEDUCTIBLE = 100;
14	const CAP_MULTIPLIER = 2;
15	const DEFAULT_INSURANCE_VALUE = 1000;
16	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
17	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
18	const FULL_PAYOUT_RATE = 1;
19	
20	type QuoteItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
21	type Damage = { itemType: string; amount: number };
22	type Incident = { cause: string; damages: Damage[] };
23	type Step =
24	  | { op: "quote"; items: QuoteItem[] }
25	  | { op: "claim"; policy: number; incident: Incident };
26	type Customer = { yearsWithMHPCO: number };
27	type Scenario = { customer: Customer; steps: Step[] };
28	
29	const BLOCK_TYPE = "block";
30	const BLOCK_OF_THREE_BASE = 60;
31	const BLOCK_SIZE = 3;
32	
33	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
34	  amulet: 60,
35	  rune: 25,
36	  moonstone: 25,
37	  [BLOCK_TYPE]: BLOCK_OF_THREE_BASE,
38	};
39	const BLOCK_TYPES = new Set(["rune", "moonstone"]);
40	
41	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
42	  sword: 1000,
43	  amulet: 600,
44	  staff: 800,
45	  potion: 400,
46	  rune: 250,
47	  moonstone: 250,
48	};
49	
50	const isKnownItemType = (type: string): boolean =>
51	  type in INSURANCE_VALUE_BY_TYPE;
52	
53	const assertKnownItemType = (item: QuoteItem): void => {
54	  if (!isKnownItemType(item.type)) {
55	    throw new Error(`Unknown item type: ${item.type}`);
56	  }
57	};
58	
59	const insuranceValueForItem = (item: QuoteItem): number =>
60	  INSURANCE_VALUE_BY_TYPE[item.type] ?? DEFAULT_INSURANCE_VALUE;
61	
62	const basePremiumForItem = (item: QuoteItem): number =>
63	  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
64	
65	const groupByType = (items: QuoteItem[]): Map<string, QuoteItem[]> =>
66	  items.reduce((groups, item) => {
67	    const group = groups.get(item.type) ?? [];
68	    return groups.set(item.type, [...group, item]);
69	  }, new Map<string, QuoteItem[]>());
70	
71	const isHighEnchantment = (item: QuoteItem): boolean =>
72	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
73	
74	const itemSurchargeRate = (item: QuoteItem): number =>
75	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
76	  (isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0) +
77	  FIRST_INSURANCE_RATE;
78	
79	const itemPremium = (item: QuoteItem): number => {
80	  const base = basePremiumForItem(item);
81	  return base + base * itemSurchargeRate(item);
82	};
83	
84	const isBlockGroup = (type: string, group: QuoteItem[]): boolean =>
85	  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE;
86	
87	const billingItems = (items: QuoteItem[]): QuoteItem[] =>
88	  [...groupByType(items)].flatMap(([type, group]) =>
89	    isBlockGroup(type, group) ? [{ type: BLOCK_TYPE }] : group,
90	  );
91	
92	const sumBy = <T>(items: T[], fn: (item: T) => number): number =>
93	  items.reduce((total, item) => total + fn(item), 0);
94	
95	const policyDiscountRate = (customer: Customer, quoteIndex: number): number =>
96	  (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0) +
97	  (quoteIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0);
98	
99	type QuoteResult = { premium: number };
100	type ClaimResult = { payout: number; remainingCap: number };
101	type StepResult = QuoteResult | ClaimResult;
102	
103	type Policy = { items: QuoteItem[]; remainingCap: number };
104	
105	const quoteStep = (
106	  customer: Customer,
107	  quoteIndex: number,
108	  items: QuoteItem[],
109	): QuoteResult => {
110	  items.forEach(assertKnownItemType);
111	  const billables = billingItems(items);
112	  const policyBase = sumBy(billables, basePremiumForItem);
113	  const subtotal = sumBy(billables, itemPremium);
114	  const discount = policyBase * policyDiscountRate(customer, quoteIndex);
115	  return { premium: Math.ceil(subtotal - discount + PROCESSING_FEE) };
116	};
117	
118	const payoutRate = (item: QuoteItem | undefined): number =>
119	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
120	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
121	    : FULL_PAYOUT_RATE;
122	
123	const findInsuredItem = (policy: Policy, itemType: string): QuoteItem | undefined =>
124	  policy.items.find((it) => it.type === itemType);
125	
126	const reimbursementForDamage = (policy: Policy, dmg: Damage): number => {
127	  const item = findInsuredItem(policy, dmg.itemType);
128	  if (item === undefined) {
129	    throw new Error(`Damaged item not insured: ${dmg.itemType}`);
130	  }
131	  return dmg.amount * payoutRate(item) - DEDUCTIBLE;
132	};
133	
134	const totalReimbursement = (policy: Policy, incident: Incident): number =>
135	  sumBy(incident.damages, (dmg) => reimbursementForDamage(policy, dmg));
136	
137	const claimStep = (policy: Policy, incident: Incident): { result: ClaimResult; policy: Policy } => {
138	  const { remainingCap: cap } = policy;
139	  const payout = Math.floor(Math.min(totalReimbursement(policy, incident), cap));
140	  const remainingCap = cap - payout;
141	  return {
142	    result: { payout, remainingCap },
143	    policy: { ...policy, remainingCap },
144	  };
145	};
146	
147	const policyFromItems = (items: QuoteItem[]): Policy => ({
148	  items,
149	  remainingCap: sumBy(items, insuranceValueForItem) * CAP_MULTIPLIER,
150	});
151	
152	type ScenarioState = {
153	  results: StepResult[];
154	  quoteIndex: number;
155	  policies: Record<number, Policy>;
156	};
157	
158	const initialState: ScenarioState = { results: [], quoteIndex: 0, policies: {} };
159	
160	const applyQuote = (
161	  customer: Customer,
162	  state: ScenarioState,
163	  items: QuoteItem[],
164	  policyId: number,
165	): ScenarioState => ({
166	  ...state,
167	  results: [...state.results, quoteStep(customer, state.quoteIndex, items)],
168	  quoteIndex: state.quoteIndex + 1,
169	  policies: { ...state.policies, [policyId]: policyFromItems(items) },
170	});
171	
172	const applyClaim = (
173	  state: ScenarioState,
174	  policyId: number,
175	  incident: Incident,
176	): ScenarioState => {
177	  const { result, policy } = claimStep(state.policies[policyId], incident);
178	  return {
179	    ...state,
180	    results: [...state.results, result],
181	    policies: { ...state.policies, [policyId]: policy },
182	  };
183	};
184	
185	const applyStep = (
186	  customer: Customer,
187	  state: ScenarioState,
188	  step: Step,
189	  index: number,
190	): ScenarioState =>
191	  step.op === "quote"
192	    ? applyQuote(customer, state, step.items, index)
193	    : applyClaim(state, step.policy, step.incident);
194	
195	export const runScenario = (scenario: unknown): unknown => {
196	  const { customer, steps } = scenario as Scenario;
197	  const { results } = steps.reduce(
198	    (state, step, index) => applyStep(customer, state, step, index),
199	    initialState,
200	  );
201	  return { results };
202	};
